patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 58137cd6f543..33d4d43c3df4 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -16064,7 +16064,27 @@ void BoUpSLP::computeMinimumValueSizes() {
                     // considered.
                     if (TE->getOpcode() == Instruction::ICmp)
                       return true;
-                    return DL->getTypeSizeInBits(U->getType()) > UserTESz;
+                                                {
+                          Type *UTy = nullptr;
+                          if (auto *I = dyn_cast<Instruction>(U)) {
+                            if (auto *SI = dyn_cast<StoreInst>(I)) {
+                              UTy = SI->getValueOperand()->getType();
+                            } else if (auto *CB = dyn_cast<CallBase>(I)) {
+                              if (llvm::is_contained(CB->args(), V))
+                                UTy = V->getType();
+                              else
+                                UTy = CB->getType();
+                            } else {
+                              UTy = I->getType();
+                            }
+                          } else {
+                            UTy = U->getType();
+                          }
+                          if (!UTy || !UTy->isSized())
+                            UTy = V->getType();
+                          return DL->getTypeSizeInBits(UTy) > UserTESz;
+                        }
+
                   }));
         })) {
       ToDemote.push_back(E.Idx);
@@ -16188,7 +16208,7 @@ void BoUpSLP::computeMinimumValueSizes() {
       isa<IntegerType>(VectorizableTree.front()->Scalars.front()->getType())) {
     for (Value *V : *UserIgnoreList) {
       auto NumSignBits = ComputeNumSignBits(V, *DL, 0, AC, nullptr, DT);
-      auto NumTypeBits = DL->getTypeSizeInBits(V->getType());
+      auto NumTypeBits = DL->getTypeSizeInBits((V->getType()->isSized() ? V->getType()->getScalarType() : VectorizableTree.front()->Scalars.front()->getType()->getScalarType()));
       unsigned BitWidth1 = NumTypeBits - NumSignBits;
       if (!isKnownNonNegative(V, SimplifyQuery(*DL)))
         ++BitWidth1;

